import{_ as i,o as l,c as e,ag as t}from"./chunks/framework.CAXxHpAX.js";const c=JSON.parse('{"title":"Hapi 远程控制配置指南","description":"","frontmatter":{},"headers":[],"relativePath":"apps/hapi.md","filePath":"apps/hapi.md"}'),p={name:"apps/hapi.md"};function s(h,a,r,o,d,n){return l(),e("div",null,[...a[0]||(a[0]=[t('<h1 id="hapi-远程控制配置指南" tabindex="-1">Hapi 远程控制配置指南 <a class="header-anchor" href="#hapi-远程控制配置指南" aria-label="Permalink to &quot;Hapi 远程控制配置指南&quot;">​</a></h1><p>随时随地远程控制你的 AI 编程助手</p><p>作者： weishu 官方文档： <a href="https://hapi.run/" target="_blank" rel="noreferrer">https://hapi.run/</a></p><p>📋 简介</p><p>Hapi 是一个本地优先的应用程序，可以让你在本地运行 Claude Code / Codex / Gemini 会话，并通过 Web / PWA / Telegram Mini App 进行远程控制。这意味着你可以在手机或浏览器上监控和管理你的 AI 编程任务。</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><table tabindex="0"><thead><tr><th>资源</th><th>地址</th></tr></thead><tbody><tr><td>Hapi 官网</td><td><a href="https://hapi.run/" target="_blank" rel="noreferrer">https://hapi.run/</a></td></tr><tr><td>Hapi 仓库</td><td><a href="https://github.com/tiann/hapi" target="_blank" rel="noreferrer">https://github.com/tiann/hapi</a></td></tr><tr><td>快速开始</td><td>官方快速开始文档</td></tr><tr><td>Cloudflare Tunnel 文档</td><td>创建远程隧道</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><p>Hapi 提供以下强大功能：</p><ul><li>✅ 多后端支持：支持 Claude Code、Codex、Gemini</li><li>✅ 进度跟踪：通过待办事项列表跟踪进度</li><li>✅ 文件浏览：浏览文件和查看 git diff</li><li>✅ 权限控制：远程批准/拒绝工具权限</li><li>✅ 移动监控：通过手机或浏览器监控和管理任务</li><li>✅ 远程会话：从任何设备发起远程会话</li><li>✅ 无缝切换：在本地原生环境和远程控制之间无缝切换</li></ul><h2 id="安装步骤" tabindex="-1">安装步骤 <a class="header-anchor" href="#安装步骤" aria-label="Permalink to &quot;安装步骤&quot;">​</a></h2><h3 id="第一步-安装-hapi" tabindex="-1">第一步：安装 Hapi <a class="header-anchor" href="#第一步-安装-hapi" aria-label="Permalink to &quot;第一步：安装 Hapi&quot;">​</a></h3><p>💡 前置要求</p><p>请确保已安装 Node.js 18+ 环境。如需安装，请参考 Node.js 环境安装。</p><p>访问 Hapi 官方快速开始文档了解详细的安装方法。</p><p>推荐使用 npx 快速启动 Hapi 服务器：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">npx</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> @twsxtd/hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> server</span></span></code></pre></div><p>启动后会显示 Token 凭证和访问地址。</p><p>⚠️ 重要提示</p><p>请务必保存好 Token 凭证！ 这是你连接和控制 Hapi 服务的唯一凭证。</p><h3 id="第二步-启动-ai-会话" tabindex="-1">第二步：启动 AI 会话 <a class="header-anchor" href="#第二步-启动-ai-会话" aria-label="Permalink to &quot;第二步：启动 AI 会话&quot;">​</a></h3><p>在项目目录下执行以下命令启动对应的 AI 服务：</p><p>启动 Claude Code：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> claude</span></span></code></pre></div><p>启动 Codex：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> codex</span></span></code></pre></div><p>启动 Gemini：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">hapi</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gemini</span></span></code></pre></div><p>启动成功后，前端界面会显示连接状态。</p><p>🎉 局域网访问</p><p>此时你已经可以在本地局域网内通过 <code>http://&lt;IP&gt;:3006</code> 访问和控制你的 AI 编程助手了！</p><h2 id="配置-cloudflare-内网穿透" tabindex="-1">配置 Cloudflare 内网穿透 <a class="header-anchor" href="#配置-cloudflare-内网穿透" aria-label="Permalink to &quot;配置 Cloudflare 内网穿透&quot;">​</a></h2><p>如果你想在任何地方（包括外网）访问你的 Hapi 服务，可以通过 Cloudflare Tunnel 实现内网穿透。</p><h3 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h3><ul><li>Cloudflare 账号（免费账号即可）</li><li>一个域名（任意域名均可）</li></ul><h3 id="配置流程" tabindex="-1">配置流程 <a class="header-anchor" href="#配置流程" aria-label="Permalink to &quot;配置流程&quot;">​</a></h3><p>按照 Cloudflare Tunnel 官方文档进行配置：</p><ol><li>登录 Cloudflare Zero Trust 控制台</li><li>创建新的 Tunnel</li><li>安装 cloudflared 客户端</li><li>配置隧道名称</li><li>配置公共主机名</li><li>设置服务地址：将服务地址设置为 <code>localhost:3006</code>（Hapi 默认端口）</li><li>完成配置</li></ol><h2 id="使用-hapi" tabindex="-1">使用 Hapi <a class="header-anchor" href="#使用-hapi" aria-label="Permalink to &quot;使用 Hapi&quot;">​</a></h2><p>配置完成后，你可以：</p><ol><li>公网访问：<code>https://your-domain.com</code>（如果配置了 Cloudflare Tunnel）</li><li>局域网访问：<code>http://&lt;IP&gt;:3006</code></li><li>本地访问：<code>http://localhost:3006</code></li></ol><p>使用步骤：</p><ol><li>打开浏览器访问 Hapi 地址</li><li>输入 Token 登录</li><li>选择要启动的 AI 后端（Claude / Codex / Gemini）</li><li>开始远程控制你的 AI 编程助手</li></ol><p>💡 使用技巧</p><ul><li>支持多设备同时连接和控制</li><li>可以安装为 PWA 应用，获得类似原生应用的体验</li><li>在手机浏览器中访问可以随时随地监控任务进度</li></ul><h2 id="安全建议" tabindex="-1">安全建议 <a class="header-anchor" href="#安全建议" aria-label="Permalink to &quot;安全建议&quot;">​</a></h2><ul><li>仅在可信网络环境下使用</li><li>定期更换 Token</li><li>如果使用公网访问，建议启用 Cloudflare 的安全功能（如 Access 策略）</li><li>不要将 Token 泄露给他人</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="提示无法连接到服务器" tabindex="-1">提示无法连接到服务器？ <a class="header-anchor" href="#提示无法连接到服务器" aria-label="Permalink to &quot;提示无法连接到服务器？&quot;">​</a></h3><ul><li>检查 Token 是否正确</li><li>确认防火墙未阻止 3006 端口</li><li>检查 Hapi 服务是否正常运行</li></ul><h3 id="cloudflare-tunnel-配置失败" tabindex="-1">Cloudflare Tunnel 配置失败？ <a class="header-anchor" href="#cloudflare-tunnel-配置失败" aria-label="Permalink to &quot;Cloudflare Tunnel 配置失败？&quot;">​</a></h3><ul><li>查看 cloudflared 日志排查问题</li><li>检查 cloudflared 客户端是否正确安装</li><li>确认域名已正确添加到 Cloudflare</li></ul><h3 id="更多问题" tabindex="-1">更多问题 <a class="header-anchor" href="#更多问题" aria-label="Permalink to &quot;更多问题&quot;">​</a></h3><p>请查看 FAQ 或访问 Hapi GitHub Issues。</p><h2 id="进阶优化" tabindex="-1">进阶优化 <a class="header-anchor" href="#进阶优化" aria-label="Permalink to &quot;进阶优化&quot;">​</a></h2><p>如果你想进一步提升 Hapi 的访问速度（特别是在国内网络环境下），可以配置 Cloudflare 优选 IP：</p><p>💡 速度优化</p><p>通过配置 Cloudflare 优选 IP，可以将访问延迟从几百毫秒降低到几十毫秒，实现接近直连的体验。</p><p>👉 查看详细教程： <a href="/apps/hapi-advanced">Hapi 进阶：Cloudflare 优选 IP 高速穿透</a></p>',59)])])}const b=i(p,[["render",s]]);export{c as __pageData,b as default};
